import{_ as s,o as e,c as n,a2 as a}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"Testing and Verification","description":"","frontmatter":{"title":"Testing and Verification","status":"complete"},"headers":[],"relativePath":"research/concepts/testing-and-verification/index.md","filePath":"research/concepts/testing-and-verification/index.md"}'),o={name:"research/concepts/testing-and-verification/index.md"};function i(r,t,l,p,c,d){return e(),n("div",null,[...t[0]||(t[0]=[a(`<h1 id="testing-and-verification" tabindex="-1">Testing and Verification <a class="header-anchor" href="#testing-and-verification" aria-label="Permalink to &quot;Testing and Verification&quot;">​</a></h1><p>Every coding agent generates code that may be wrong. Unlike human developers who build mental models of correctness through years of experience, LLMs produce plausible-looking code without any inherent verification mechanism. Testing and verification is the <strong>primary feedback signal</strong> that transforms unreliable code generation into reliable code editing. This document synthesizes the verification patterns, strategies, and architectural decisions observed across 17 real-world agent implementations.</p><p>The impact is stark: without verification loops, agents succeed roughly 30–40% of the time on benchmarks like SWE-bench. With proper <strong>Edit-Apply-Verify</strong> cycles, the same agents reach 60–80%+ pass rates. Verification is not a nice-to-have — it is the single largest lever for agent accuracy.</p><hr><h2 id="why-testing-matters-for-coding-agents" tabindex="-1">Why Testing Matters for Coding Agents <a class="header-anchor" href="#why-testing-matters-for-coding-agents" aria-label="Permalink to &quot;Why Testing Matters for Coding Agents&quot;">​</a></h2><p>Humans verify code through a combination of mental simulation, type intuition, and experience-based pattern matching. An experienced developer &quot;knows&quot; that off-by-one errors lurk in loop boundaries and checks carefully. LLMs have none of this — they produce the most statistically likely next token, which correlates with correctness but does not guarantee it.</p><h3 id="the-failure-modes-without-verification" tabindex="-1">The Failure Modes Without Verification <a class="header-anchor" href="#the-failure-modes-without-verification" aria-label="Permalink to &quot;The Failure Modes Without Verification&quot;">​</a></h3><ol><li><strong>Silent incorrectness</strong> — Code that parses, compiles, and looks reasonable but produces wrong results. LLMs are particularly prone to this because they optimize for plausibility, not correctness.</li><li><strong>Import/dependency drift</strong> — The model references a function, class, or module that doesn&#39;t exist in the current codebase. Without a build or import check, this goes undetected until runtime.</li><li><strong>Syntax errors in unfamiliar languages</strong> — Models trained predominantly on Python/JS make subtle syntax mistakes in Rust, Go, or Haskell. A syntax check catches these instantly.</li><li><strong>Stale context hallucination</strong> — The model &quot;remembers&quot; a function signature from training data that has since changed. Type checking or build verification catches the mismatch.</li><li><strong>Partial edits</strong> — The model edits one file but forgets to update a dependent file. Integration tests or build verification reveal the breakage.</li></ol><h3 id="the-quantitative-case" tabindex="-1">The Quantitative Case <a class="header-anchor" href="#the-quantitative-case" aria-label="Permalink to &quot;The Quantitative Case&quot;">​</a></h3><p>Evidence from multiple sources converges on the same conclusion:</p><table tabindex="0"><thead><tr><th>Condition</th><th>SWE-bench Pass Rate (approx.)</th></tr></thead><tbody><tr><td>Single-shot generation, no verification</td><td>25–35%</td></tr><tr><td>Generation + lint feedback loop</td><td>40–50%</td></tr><tr><td>Generation + lint + test feedback loop</td><td>55–70%</td></tr><tr><td>Multi-agent + verification enforcement</td><td>65–80%+</td></tr></tbody></table><p>ForgeCode&#39;s benchmark results are the most explicit: programmatic verification enforcement was described as the <strong>&quot;single biggest score improvement&quot;</strong> on TermBench. The difference between prompting the model to verify and <em>forcing</em> verification through the runtime was the inflection point.</p><hr><h2 id="the-edit-apply-verify-pattern" tabindex="-1">The Edit-Apply-Verify Pattern <a class="header-anchor" href="#the-edit-apply-verify-pattern" aria-label="Permalink to &quot;The Edit-Apply-Verify Pattern&quot;">​</a></h2><p>The <strong>Edit-Apply-Verify</strong> (E-A-V) pattern is the fundamental loop that underlies every successful coding agent. It is the verification-aware extension of the basic <strong>ReAct</strong> agentic loop.</p><h3 id="the-universal-pseudocode" tabindex="-1">The Universal Pseudocode <a class="header-anchor" href="#the-universal-pseudocode" aria-label="Permalink to &quot;The Universal Pseudocode&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>messages = [system_prompt, user_task]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>while true:</span></span>
<span class="line"><span>    response = llm.generate(messages)</span></span>
<span class="line"><span>    messages.append(response)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    edits = parse_edits(response)</span></span>
<span class="line"><span>    if edits is empty:</span></span>
<span class="line"><span>        break                              # model is done</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    # --- APPLY ---</span></span>
<span class="line"><span>    for edit in edits:</span></span>
<span class="line"><span>        apply_to_file(edit)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    # --- VERIFY ---</span></span>
<span class="line"><span>    errors = []</span></span>
<span class="line"><span>    if config.auto_lint:</span></span>
<span class="line"><span>        lint_result = run_lint()</span></span>
<span class="line"><span>        if lint_result.failed:</span></span>
<span class="line"><span>            errors.append(lint_result.output)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    if config.auto_test:</span></span>
<span class="line"><span>        test_result = run_tests()</span></span>
<span class="line"><span>        if test_result.failed:</span></span>
<span class="line"><span>            errors.append(test_result.output)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    if errors:</span></span>
<span class="line"><span>        error_msg = truncate(join(errors), max_lines=50)</span></span>
<span class="line"><span>        messages.append(error_message(error_msg))</span></span>
<span class="line"><span>        continue                           # retry with error context</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    commit_changes()</span></span></code></pre></div><p>This is not a simplification — it directly mirrors implementations across agents. The critical insight is that the <strong>verify</strong> step closes the feedback loop. Without it, the agent is flying blind after every edit.</p><h3 id="aider-the-gold-standard" tabindex="-1">Aider: The Gold Standard <a class="header-anchor" href="#aider-the-gold-standard" aria-label="Permalink to &quot;Aider: The Gold Standard&quot;">​</a></h3><p>Aider&#39;s implementation is the most explicit and well-documented E-A-V loop. Its architecture cleanly separates the edit, apply, lint, and test phases:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Simplified from Aider&#39;s core loop</span></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> run_one_round</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> user_message</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # 1. EDIT: Get LLM response with code changes</span></span>
<span class="line"><span style="color:#CDD6F4;">    content </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">send_to_llm</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # 2. APPLY: Parse and apply edits to files</span></span>
<span class="line"><span style="color:#CDD6F4;">    edits </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">get_edits</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">content</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">apply_edits</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">edits</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # 3. VERIFY (lint): Run linter if configured</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">auto_lint</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">        lint_errors </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">linter</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">run</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">get_dirty_files</span><span style="color:#9399B2;">())</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#CDD6F4;"> lint_errors</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">            self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">auto_commit</span><span style="color:#9399B2;">()</span><span style="color:#6C7086;font-style:italic;">  # commit what we have</span></span>
<span class="line"><span style="color:#CDD6F4;">            lint_output </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">linter</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">format_errors</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">lint_errors</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">            # Feed errors back — bounded retry</span></span>
<span class="line"><span style="color:#CBA6F7;">            return</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">send_to_llm</span><span style="color:#9399B2;">([</span></span>
<span class="line"><span style="color:#A6E3A1;font-style:italic;">                f</span><span style="color:#A6E3A1;">&quot;Fix these lint errors:</span><span style="color:#F5C2E7;">\\n{</span><span style="color:#CDD6F4;">lint_output</span><span style="color:#F5C2E7;">}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#9399B2;">            ])</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # 4. VERIFY (test): Run tests if configured</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">auto_test</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">        test_result </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">commands</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">cmd_test</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">test_cmd</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#CDD6F4;"> test_result</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">exit_code </span><span style="color:#94E2D5;">!=</span><span style="color:#FAB387;"> 0</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">            self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">auto_commit</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#CDD6F4;">            test_output </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> truncate</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">test_result</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">output</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 50</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">            return</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">send_to_llm</span><span style="color:#9399B2;">([</span></span>
<span class="line"><span style="color:#A6E3A1;font-style:italic;">                f</span><span style="color:#A6E3A1;">&quot;Fix these test failures:</span><span style="color:#F5C2E7;">\\n{</span><span style="color:#CDD6F4;">test_output</span><span style="color:#F5C2E7;">}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#9399B2;">            ])</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # 5. COMMIT: All checks passed</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">auto_commit</span><span style="color:#9399B2;">()</span></span></code></pre></div><p>Key design decisions in Aider&#39;s implementation:</p><ol><li><strong>Lint runs before tests</strong> — Lint errors are fast to detect and usually fast to fix. Running lint first avoids wasting time on test execution when there are obvious syntax/style issues.</li><li><strong>Auto-commit between retry rounds</strong> — Each attempt is committed separately, creating a clean git history and enabling rollback.</li><li><strong>Output truncation to 50 lines</strong> — Aider deliberately truncates error output. More context actually <em>hurts</em> — the model gets confused by long tracebacks and tries to fix symptoms rather than root causes.</li><li><strong>Bounded retries</strong> — On benchmarks, Aider uses 2 attempts maximum. Diminishing returns set in quickly.</li></ol><h3 id="junie-cli-first-class-verification-phase" tabindex="-1">Junie CLI: First-Class Verification Phase <a class="header-anchor" href="#junie-cli-first-class-verification-phase" aria-label="Permalink to &quot;Junie CLI: First-Class Verification Phase&quot;">​</a></h3><p>Junie CLI elevates verification from an optional step to a <strong>mandatory phase</strong> in its execution pipeline:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Understand → Plan → Implement → Verify → Diagnose</span></span></code></pre></div><p>Verification is not something the user must invoke — it is an integral part of every task. If verification fails, the agent enters a <strong>Diagnose</strong> phase that analyzes failures with a potentially different (more capable) model before retrying implementation.</p><hr><h2 id="the-verification-hierarchy" tabindex="-1">The Verification Hierarchy <a class="header-anchor" href="#the-verification-hierarchy" aria-label="Permalink to &quot;The Verification Hierarchy&quot;">​</a></h2><p>Not all verification is equal. Faster checks should run first — they catch cheap errors before expensive verification runs. This forms a natural hierarchy:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>                          ┌─────────────────────┐</span></span>
<span class="line"><span>                          │  Level 7: Self-     │</span></span>
<span class="line"><span>                          │  Review (re-read    │  Seconds</span></span>
<span class="line"><span>                          │  code, diff review) │</span></span>
<span class="line"><span>                        ┌─┴─────────────────────┴─┐</span></span>
<span class="line"><span>                        │  Level 6: Integration    │</span></span>
<span class="line"><span>                        │  Tests                   │  Minutes</span></span>
<span class="line"><span>                      ┌─┴─────────────────────────┴─┐</span></span>
<span class="line"><span>                      │  Level 5: Unit Tests         │</span></span>
<span class="line"><span>                      │                              │  Seconds–Minutes</span></span>
<span class="line"><span>                    ┌─┴─────────────────────────────┴─┐</span></span>
<span class="line"><span>                    │  Level 4: Build (compile,        │</span></span>
<span class="line"><span>                    │  bundle, link)                    │  Seconds–Minutes</span></span>
<span class="line"><span>                  ┌─┴─────────────────────────────────┴─┐</span></span>
<span class="line"><span>                  │  Level 3: Type Check (tsc, mypy,     │</span></span>
<span class="line"><span>                  │  pyright)                             │  Seconds</span></span>
<span class="line"><span>                ┌─┴─────────────────────────────────────┴─┐</span></span>
<span class="line"><span>                │  Level 2: Lint (ESLint, Ruff, pylint)    │</span></span>
<span class="line"><span>                │                                          │  Seconds</span></span>
<span class="line"><span>              ┌─┴─────────────────────────────────────────┴─┐</span></span>
<span class="line"><span>              │  Level 1: Syntax Check (parse, tree-sitter)  │</span></span>
<span class="line"><span>              │                                              │  Milliseconds</span></span>
<span class="line"><span>              └──────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>              FAST / CHEAP ──────────────────────► SLOW / EXPENSIVE</span></span></code></pre></div><h3 id="level-1-syntax-checking" tabindex="-1">Level 1: Syntax Checking <a class="header-anchor" href="#level-1-syntax-checking" aria-label="Permalink to &quot;Level 1: Syntax Checking&quot;">​</a></h3><p>The cheapest verification. Tree-sitter can parse a file in single-digit milliseconds and immediately detect malformed code. Several agents use tree-sitter for pre-verification before even attempting to run external tools:</p><ul><li><strong>Aider</strong> uses tree-sitter to validate that edits produce syntactically valid code before committing</li><li><strong>Claude Code</strong> validates edit results through syntax parsing</li><li><strong>ForgeCode</strong> catches malformed tool calls at the schema level</li></ul><h3 id="level-2-linting" tabindex="-1">Level 2: Linting <a class="header-anchor" href="#level-2-linting" aria-label="Permalink to &quot;Level 2: Linting&quot;">​</a></h3><p>Lint catches style violations, unused imports, undefined variables, and common anti-patterns. Agents configure linting through different mechanisms:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Lint Configuration</th><th>Auto-Lint</th></tr></thead><tbody><tr><td><strong>Aider</strong></td><td><code>--lint-cmd</code> flag per language</td><td>Yes (<code>--auto-lint</code>)</td></tr><tr><td><strong>Claude Code</strong></td><td>Model-driven (agent decides when to lint)</td><td>Model&#39;s discretion</td></tr><tr><td><strong>OpenCode</strong></td><td>User-configured via settings</td><td>Optional</td></tr><tr><td><strong>Goose</strong></td><td>Extension-provided lint commands</td><td>Extension-dependent</td></tr><tr><td><strong>Warp</strong></td><td>Active AI error detection in terminal</td><td>Yes (automatic)</td></tr></tbody></table><h3 id="level-3-type-checking" tabindex="-1">Level 3: Type Checking <a class="header-anchor" href="#level-3-type-checking" aria-label="Permalink to &quot;Level 3: Type Checking&quot;">​</a></h3><p>Type checkers (tsc, mypy, pyright) catch a class of errors that linters miss — wrong argument types, missing return values, incompatible interfaces. They are particularly valuable for agents because LLMs frequently hallucinate function signatures.</p><h3 id="level-4-build-verification" tabindex="-1">Level 4: Build Verification <a class="header-anchor" href="#level-4-build-verification" aria-label="Permalink to &quot;Level 4: Build Verification&quot;">​</a></h3><p>Compilation and bundling catch linking errors, missing dependencies, and module resolution failures. For compiled languages (Rust, Go, Java), the build step is the primary verification mechanism.</p><h3 id="level-5–6-unit-and-integration-tests" tabindex="-1">Level 5–6: Unit and Integration Tests <a class="header-anchor" href="#level-5–6-unit-and-integration-tests" aria-label="Permalink to &quot;Level 5–6: Unit and Integration Tests&quot;">​</a></h3><p>Tests are the highest-signal verification. A passing test suite means the code <em>works</em>, not just that it <em>looks right</em>. This is the level where most agents focus their verification effort.</p><h3 id="level-7-self-review" tabindex="-1">Level 7: Self-Review <a class="header-anchor" href="#level-7-self-review" aria-label="Permalink to &quot;Level 7: Self-Review&quot;">​</a></h3><p>Some agents re-read their own output, review diffs, or run a separate &quot;reviewer&quot; pass. This catches logical errors that automated tools miss. Claude Code&#39;s three-phase loop includes a verify phase where the model reviews its own changes. Capy&#39;s Captain/Build separation creates a natural review boundary.</p><hr><h2 id="how-agents-approach-verification" tabindex="-1">How Agents Approach Verification <a class="header-anchor" href="#how-agents-approach-verification" aria-label="Permalink to &quot;How Agents Approach Verification&quot;">​</a></h2><p>Agents fall into three distinct philosophies for when and how verification runs. The choice has profound implications for reliability.</p><h3 id="philosophy-1-model-driven-verification" tabindex="-1">Philosophy 1: Model-Driven Verification <a class="header-anchor" href="#philosophy-1-model-driven-verification" aria-label="Permalink to &quot;Philosophy 1: Model-Driven Verification&quot;">​</a></h3><p>The agent&#39;s LLM decides what to verify, when to verify, and how to interpret results. No external enforcement exists — the model must choose to run tests.</p><p><strong>Representatives</strong>: <strong>Claude Code</strong>, <strong>Codex</strong>, <strong>Goose</strong>, <strong>Gemini CLI</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────────────┐</span></span>
<span class="line"><span>│              LLM decides:              │</span></span>
<span class="line"><span>│  &quot;I should run the tests now&quot;          │</span></span>
<span class="line"><span>│  &quot;Let me check if this compiles&quot;       │</span></span>
<span class="line"><span>│  &quot;I&#39;ll review my changes&quot;              │</span></span>
<span class="line"><span>└────────────┬───────────────────────────┘</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>             ▼</span></span>
<span class="line"><span>    Tool call: run_command(&quot;npm test&quot;)</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>             ▼</span></span>
<span class="line"><span>    Results feed back into conversation</span></span></code></pre></div><p><strong>Strengths</strong>: Maximum flexibility. The model can skip verification when it&#39;s confident (e.g., trivial typo fix) and run extensive verification when uncertain (e.g., complex refactor). Adapts to context naturally.</p><p><strong>Weaknesses</strong>: Models skip verification ~40% of the time when it&#39;s optional. Prompt instructions like &quot;always run tests after editing&quot; are followed inconsistently. Under context pressure, verification is the first thing the model drops.</p><h3 id="philosophy-2-framework-enforced-verification" tabindex="-1">Philosophy 2: Framework-Enforced Verification <a class="header-anchor" href="#philosophy-2-framework-enforced-verification" aria-label="Permalink to &quot;Philosophy 2: Framework-Enforced Verification&quot;">​</a></h3><p>The runtime programmatically requires verification. The agent cannot mark a task as complete without passing through a verification gate.</p><p><strong>Representatives</strong>: <strong>ForgeCode</strong>, <strong>Junie CLI</strong>, <strong>Droid</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────────────┐</span></span>
<span class="line"><span>│           Runtime enforces:            │</span></span>
<span class="line"><span>│  edit_file() → auto_lint()             │</span></span>
<span class="line"><span>│  task_complete() → BLOCKED until       │</span></span>
<span class="line"><span>│    verification_passed == true         │</span></span>
<span class="line"><span>└────────────┬───────────────────────────┘</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>             ▼</span></span>
<span class="line"><span>    Verification runs automatically</span></span>
<span class="line"><span>    regardless of model&#39;s preference</span></span></code></pre></div><p>ForgeCode&#39;s approach is the most explicit. The runtime intercepts task completion and programmatically inserts a verification step. The model cannot skip it — verification is a <strong>runtime invariant</strong>, not a prompt suggestion. This was the architectural decision that produced the single biggest score improvement on TermBench.</p><p>Junie CLI makes verification a first-class phase (Understand → Plan → Implement → <strong>Verify</strong> → Diagnose). The phase boundary is structural — the agent transitions through it as part of its normal execution flow.</p><p><strong>Strengths</strong>: Consistent verification regardless of model quality or context pressure. Catches the ~40% of cases where models would skip verification.</p><p><strong>Weaknesses</strong>: Less flexible — may run unnecessary verification on trivial changes. Adds latency to every edit cycle.</p><h3 id="philosophy-3-user-configured-verification" tabindex="-1">Philosophy 3: User-Configured Verification <a class="header-anchor" href="#philosophy-3-user-configured-verification" aria-label="Permalink to &quot;Philosophy 3: User-Configured Verification&quot;">​</a></h3><p>The user specifies exactly which commands to run. The agent executes them mechanically.</p><p><strong>Representatives</strong>: <strong>Aider</strong>, <strong>OpenCode</strong>, <strong>mini-SWE-agent</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span># User configures at startup:</span></span>
<span class="line"><span>aider --auto-lint --lint-cmd &quot;ruff check&quot; \\</span></span>
<span class="line"><span>      --auto-test --test-cmd &quot;pytest tests/&quot;</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────────────┐</span></span>
<span class="line"><span>│         User configures:               │</span></span>
<span class="line"><span>│  lint_cmd = &quot;ruff check&quot;               │</span></span>
<span class="line"><span>│  test_cmd = &quot;pytest tests/&quot;            │</span></span>
<span class="line"><span>│  auto_lint = true                      │</span></span>
<span class="line"><span>│  auto_test = true                      │</span></span>
<span class="line"><span>└────────────┬───────────────────────────┘</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>             ▼</span></span>
<span class="line"><span>    After every edit:</span></span>
<span class="line"><span>      1. Run lint_cmd → feed errors back</span></span>
<span class="line"><span>      2. Run test_cmd → feed errors back</span></span></code></pre></div><p><strong>Strengths</strong>: Deterministic — the exact same verification runs every time. User controls cost/speed tradeoff. Works with any language/framework.</p><p><strong>Weaknesses</strong>: Requires user configuration. Wrong test command = wrong feedback. No adaptive verification based on change scope.</p><h3 id="philosophy-comparison" tabindex="-1">Philosophy Comparison <a class="header-anchor" href="#philosophy-comparison" aria-label="Permalink to &quot;Philosophy Comparison&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspect</th><th>Model-Driven</th><th>Framework-Enforced</th><th>User-Configured</th></tr></thead><tbody><tr><td><strong>Consistency</strong></td><td>Low (~60% of the time)</td><td>High (always runs)</td><td>High (always runs)</td></tr><tr><td><strong>Flexibility</strong></td><td>High</td><td>Low</td><td>Medium</td></tr><tr><td><strong>Configuration</strong></td><td>None</td><td>None</td><td>Required</td></tr><tr><td><strong>Overhead</strong></td><td>Variable</td><td>Fixed per edit</td><td>Fixed per edit</td></tr><tr><td><strong>Best for</strong></td><td>Capable models, varied tasks</td><td>Benchmarks, CI</td><td>Known codebases</td></tr><tr><td><strong>Agents</strong></td><td>Claude Code, Codex, Goose</td><td>ForgeCode, Junie, Droid</td><td>Aider, OpenCode</td></tr></tbody></table><hr><h2 id="enforce-don-t-prompt" tabindex="-1">Enforce, Don&#39;t Prompt <a class="header-anchor" href="#enforce-don-t-prompt" aria-label="Permalink to &quot;Enforce, Don&#39;t Prompt&quot;">​</a></h2><p>This is the single most important insight in agent verification design:</p><blockquote><p><strong>Models skip optional verification ~40% of the time. Building verification into the runtime — not the prompt — is the key architectural decision.</strong></p></blockquote><p>ForgeCode&#39;s experience is the clearest evidence. Their agents were prompted to verify. They did — sometimes. Programmatic enforcement made verification happen 100% of the time. The result: the <strong>single biggest score improvement</strong> on TermBench.</p><p>Why do models skip verification?</p><ol><li><strong>Token economics</strong> — Under context pressure, the model optimizes for brevity. Verification adds tokens. The model &quot;decides&quot; it&#39;s done.</li><li><strong>Confidence miscalibration</strong> — LLMs are overconfident. A model that generates code rates its own output highly, reducing the perceived need for verification.</li><li><strong>Instruction decay</strong> — In long conversations, system prompt instructions lose influence. &quot;Always run tests&quot; in the system prompt is followed less as the conversation grows.</li><li><strong>Prompt saturation</strong> — Too many instructions compete for attention. &quot;Verify your work&quot; competes with &quot;be concise&quot;, &quot;follow the user&#39;s style&quot;, &quot;use idiomatic patterns&quot;, etc.</li></ol><p>The enforcement pattern in pseudocode:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">class</span><span style="color:#F9E2AF;font-style:italic;"> VerificationEnforcer</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;&quot;&quot;Runtime enforcement — model cannot skip verification.&quot;&quot;&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    def</span><span style="color:#89B4FA;font-style:italic;"> complete_task</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> agent_state</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        # Agent says it&#39;s done — but we check first</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#CBA6F7;"> not</span><span style="color:#CDD6F4;"> agent_state</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">verification_passed</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">            # Force a verification round</span></span>
<span class="line"><span style="color:#CDD6F4;">            lint_result </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">run_lint</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">agent_state</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">changed_files</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">            test_result </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">run_tests</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">agent_state</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">test_command</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">            if</span><span style="color:#CDD6F4;"> lint_result</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">failed </span><span style="color:#CBA6F7;">or</span><span style="color:#CDD6F4;"> test_result</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">failed</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">                # Feed errors back — agent MUST address them</span></span>
<span class="line"><span style="color:#CDD6F4;">                agent_state</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">add_message</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#A6E3A1;font-style:italic;">                    f</span><span style="color:#A6E3A1;">&quot;Verification failed. Fix before completing:</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;font-style:italic;">                    f</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#F5C2E7;">{</span><span style="color:#CDD6F4;">lint_result</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">errors</span><span style="color:#F5C2E7;">}\\n{</span><span style="color:#CDD6F4;">test_result</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">errors</span><span style="color:#F5C2E7;">}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#9399B2;">                )</span></span>
<span class="line"><span style="color:#CBA6F7;">                return</span><span style="color:#CDD6F4;"> TaskStatus</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">NEEDS_RETRY</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">            agent_state</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">verification_passed </span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;"> True</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#CDD6F4;"> TaskStatus</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">COMPLETE</span></span></code></pre></div><p>The pattern generalizes: any behavior you want the agent to reliably exhibit should be enforced by the runtime, not requested by the prompt. This applies beyond verification — to file backups, git commits, permission checks, and context management.</p><hr><h2 id="the-verification-feedback-loop" tabindex="-1">The Verification Feedback Loop <a class="header-anchor" href="#the-verification-feedback-loop" aria-label="Permalink to &quot;The Verification Feedback Loop&quot;">​</a></h2><p>How error output feeds back into the agent&#39;s context is a critical design decision. Too little output and the model can&#39;t diagnose the problem. Too much and the model gets confused.</p><h3 id="truncation-strategies" tabindex="-1">Truncation Strategies <a class="header-anchor" href="#truncation-strategies" aria-label="Permalink to &quot;Truncation Strategies&quot;">​</a></h3><p><strong>Aider&#39;s 50-line rule</strong> is the most well-studied approach. Aider truncates all error output to approximately 50 lines before feeding it back to the model. The reasoning:</p><ol><li><strong>Long tracebacks contain noise</strong> — A 200-line Python traceback has maybe 5 relevant lines. The model tries to &quot;fix&quot; lines that aren&#39;t errors.</li><li><strong>Token budget competition</strong> — Error output competes with code context for the limited context window. 200 lines of traceback may push out the actual code being edited.</li><li><strong>Focused errors produce focused fixes</strong> — A concise error message like <code>TypeError: expected str, got int at line 42</code> is more actionable than the full traceback.</li></ol><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Aider&#39;s truncation approach</span></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> truncate_output</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">output</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> max_lines</span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;">50</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CDD6F4;">    lines </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> output</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">strip</span><span style="color:#9399B2;">().</span><span style="color:#89B4FA;">splitlines</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#FAB387;font-style:italic;"> len</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">lines</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> &lt;=</span><span style="color:#CDD6F4;"> max_lines</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#CDD6F4;"> output</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # Keep first and last lines (most informative)</span></span>
<span class="line"><span style="color:#CDD6F4;">    half </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> max_lines </span><span style="color:#94E2D5;">//</span><span style="color:#FAB387;"> 2</span></span>
<span class="line"><span style="color:#CDD6F4;">    truncated </span><span style="color:#94E2D5;">=</span><span style="color:#EBA0AC;font-style:italic;"> lines</span><span style="color:#9399B2;">[:</span><span style="color:#EBA0AC;font-style:italic;">half</span><span style="color:#9399B2;">]</span><span style="color:#94E2D5;"> +</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#A6E3A1;font-style:italic;">        f</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">... (</span><span style="color:#F5C2E7;">{</span><span style="color:#FAB387;font-style:italic;">len</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">lines</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -</span><span style="color:#CDD6F4;"> max_lines</span><span style="color:#F5C2E7;">}</span><span style="color:#A6E3A1;"> lines truncated) ...</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    ]</span><span style="color:#94E2D5;"> +</span><span style="color:#EBA0AC;font-style:italic;"> lines</span><span style="color:#9399B2;">[</span><span style="color:#94E2D5;">-</span><span style="color:#EBA0AC;font-style:italic;">half</span><span style="color:#9399B2;">:]</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">join</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">truncated</span><span style="color:#9399B2;">)</span></span></code></pre></div><h3 id="structured-vs-raw-errors" tabindex="-1">Structured vs. Raw Errors <a class="header-anchor" href="#structured-vs-raw-errors" aria-label="Permalink to &quot;Structured vs. Raw Errors&quot;">​</a></h3><p>Some agents structure error output before feeding it back:</p><table tabindex="0"><thead><tr><th>Approach</th><th>Agent</th><th>Example</th></tr></thead><tbody><tr><td><strong>Raw output</strong></td><td>mini-SWE-agent, Aider</td><td>Pass command stdout/stderr directly</td></tr><tr><td><strong>Structured extraction</strong></td><td>ForgeCode, Warp</td><td>Parse errors into file:line:message format</td></tr><tr><td><strong>Classified errors</strong></td><td>OpenHands, Droid</td><td>Categorize as syntax/type/runtime/test errors</td></tr><tr><td><strong>AI-interpreted</strong></td><td>Warp</td><td>Use AI to analyze terminal output for errors</td></tr></tbody></table><p>Warp&#39;s approach is unique: its <strong>Active AI Error Detection</strong> monitors terminal output in real-time and uses a model to identify errors, even in non-standard output formats. This catches errors that regex-based parsers miss.</p><h3 id="error-classification" tabindex="-1">Error Classification <a class="header-anchor" href="#error-classification" aria-label="Permalink to &quot;Error Classification&quot;">​</a></h3><p>Some agents classify errors to determine the appropriate response:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Syntax error     → Re-edit the file (fast fix)</span></span>
<span class="line"><span>Type error       → Check function signatures, fix types</span></span>
<span class="line"><span>Import error     → Check available modules, fix imports</span></span>
<span class="line"><span>Test failure     → Analyze assertion, understand expected vs actual</span></span>
<span class="line"><span>Build error      → Check dependencies, configuration</span></span>
<span class="line"><span>Runtime error    → Add error handling, fix logic</span></span></code></pre></div><p>This classification helps the agent focus its retry attempt rather than blindly re-generating code.</p><hr><h2 id="bounded-retries" tabindex="-1">Bounded Retries <a class="header-anchor" href="#bounded-retries" aria-label="Permalink to &quot;Bounded Retries&quot;">​</a></h2><p>Retrying verification failures improves success rates — but with rapidly diminishing returns. The empirical sweet spot across agents is <strong>2–3 retries</strong>.</p><h3 id="why-retries-have-diminishing-returns" tabindex="-1">Why Retries Have Diminishing Returns <a class="header-anchor" href="#why-retries-have-diminishing-returns" aria-label="Permalink to &quot;Why Retries Have Diminishing Returns&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Success Rate by Retry Attempt (approximate):</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Attempt 1 (initial):  ████████████████████░░░░░░░░░░  60%</span></span>
<span class="line"><span>Attempt 2 (+retry 1): █████████████████████████░░░░░  75%</span></span>
<span class="line"><span>Attempt 3 (+retry 2): ██████████████████████████░░░░  80%</span></span>
<span class="line"><span>Attempt 4 (+retry 3): ██████████████████████████░░░░  81%</span></span>
<span class="line"><span>Attempt 5 (+retry 4): ███████████████████████████░░░  82%</span></span>
<span class="line"><span>                       ──────────────────────────────</span></span>
<span class="line"><span>                       Diminishing returns after retry 2</span></span></code></pre></div><p>The first retry catches the majority of fixable errors — typos, missing imports, off-by-one errors. The second retry catches subtler issues. By the third retry, the model is typically stuck in a loop, regenerating the same incorrect approach.</p><h3 id="agent-specific-retry-bounds" tabindex="-1">Agent-Specific Retry Bounds <a class="header-anchor" href="#agent-specific-retry-bounds" aria-label="Permalink to &quot;Agent-Specific Retry Bounds&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Max Retries</th><th>Mechanism</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Aider</strong></td><td>2 attempts on benchmark</td><td><code>--map-auto-retries</code></td><td>Deliberately conservative</td></tr><tr><td><strong>ForgeCode</strong></td><td><code>max_tool_failure_per_turn</code></td><td>Configurable per-turn limit</td><td>Prevents cascading failures</td></tr><tr><td><strong>OpenHands</strong></td><td>8 retries</td><td>StuckDetector</td><td>Detects repetitive actions</td></tr><tr><td><strong>Codex</strong></td><td>Context-dependent</td><td>Auto-compaction at 90%</td><td>Retries until context full</td></tr><tr><td><strong>Junie CLI</strong></td><td>Phase-based</td><td>Diagnose phase on failure</td><td>Escalates to stronger model</td></tr><tr><td><strong>mini-SWE-agent</strong></td><td>Fixed iteration limit</td><td><code>max_steps</code> parameter</td><td>Hard stop after N steps</td></tr><tr><td><strong>Goose</strong></td><td>Configurable</td><td>Extension-dependent</td><td>Varies by verification type</td></tr></tbody></table><h3 id="stuck-detection" tabindex="-1">Stuck Detection <a class="header-anchor" href="#stuck-detection" aria-label="Permalink to &quot;Stuck Detection&quot;">​</a></h3><p>OpenHands implements a <strong>StuckDetector</strong> that identifies when the agent is looping without progress:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Simplified from OpenHands&#39; stuck detection</span></span>
<span class="line"><span style="color:#CBA6F7;">class</span><span style="color:#F9E2AF;font-style:italic;"> StuckDetector</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">    def</span><span style="color:#89B4FA;font-style:italic;"> is_stuck</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> history</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CDD6F4;">        recent_actions </span><span style="color:#94E2D5;">=</span><span style="color:#EBA0AC;font-style:italic;"> history</span><span style="color:#9399B2;">[</span><span style="color:#94E2D5;">-</span><span style="color:#FAB387;font-style:italic;">4</span><span style="color:#9399B2;">:]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        # Same action repeated 3+ times</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#89B4FA;"> all_identical</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">recent_actions</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CBA6F7;">            return</span><span style="color:#CBA6F7;"> True</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        # Alternating between two actions (edit/undo cycle)</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#89B4FA;"> is_oscillating</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">recent_actions</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CBA6F7;">            return</span><span style="color:#CBA6F7;"> True</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        # Same error message appearing repeatedly</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#89B4FA;"> same_error_repeated</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">recent_actions</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> threshold</span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;">3</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CBA6F7;">            return</span><span style="color:#CBA6F7;"> True</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#CBA6F7;"> False</span></span></code></pre></div><p>When stuck, agents take different recovery actions:</p><ol><li><strong>Stop and report</strong> — mini-SWE-agent, Aider (on benchmark)</li><li><strong>Escalate to stronger model</strong> — Junie CLI (Diagnose phase uses Opus)</li><li><strong>Compact context and retry</strong> — Codex (auto-compaction)</li><li><strong>Delegate to different agent</strong> — ForgeCode (Forge → Sage for research)</li><li><strong>Rollback and retry differently</strong> — Codex (undo support)</li></ol><hr><h2 id="rollback-and-recovery" tabindex="-1">Rollback and Recovery <a class="header-anchor" href="#rollback-and-recovery" aria-label="Permalink to &quot;Rollback and Recovery&quot;">​</a></h2><p>When verification fails repeatedly, agents need a way to undo changes and try a different approach. Rollback strategies vary significantly:</p><h3 id="git-based-rollback" tabindex="-1">Git-Based Rollback <a class="header-anchor" href="#git-based-rollback" aria-label="Permalink to &quot;Git-Based Rollback&quot;">​</a></h3><p><strong>Aider</strong> commits after every successful edit, creating natural rollback points:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>commit 1: Initial edit attempt</span></span>
<span class="line"><span>commit 2: Lint fix</span></span>
<span class="line"><span>commit 3: Test fix (PASSES) ← keep this</span></span>
<span class="line"><span>--- or ---</span></span>
<span class="line"><span>commit 1: Initial edit attempt</span></span>
<span class="line"><span>commit 2: Lint fix</span></span>
<span class="line"><span>commit 3: Test fix (STILL FAILS) ← rollback to before commit 1</span></span></code></pre></div><h3 id="checkpoint-based-rollback" tabindex="-1">Checkpoint-Based Rollback <a class="header-anchor" href="#checkpoint-based-rollback" aria-label="Permalink to &quot;Checkpoint-Based Rollback&quot;">​</a></h3><p><strong>Codex</strong> maintains <code>GhostSnapshot</code> items that survive context compaction, enabling undo:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Codex&#39;s undo mechanism</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">Op</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Undo</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> n_turns </span><span style="color:#9399B2;">}</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Revert conversation state to N turns ago</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // GhostSnapshots preserve enough state for redo</span></span>
<span class="line"><span style="color:#CDD6F4;">    context_manager</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">undo</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">n_turns</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Claude Code</strong> implements checkpoints that capture both conversation state and file state, allowing rewind to any previous point.</p><h3 id="runtime-state-tracking" tabindex="-1">Runtime State Tracking <a class="header-anchor" href="#runtime-state-tracking" aria-label="Permalink to &quot;Runtime State Tracking&quot;">​</a></h3><p><strong>ForgeCode</strong> tracks changed files and can revert to the state before the current turn:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Revert all changes from current turn</span></span>
<span class="line"><span style="color:#CBA6F7;">for</span><span style="color:#CDD6F4;"> file_path</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> original_content </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> turn_state</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">file_snapshots</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">items</span><span style="color:#9399B2;">():</span></span>
<span class="line"><span style="color:#89B4FA;">    write_file</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">file_path</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> original_content</span><span style="color:#9399B2;">)</span></span></code></pre></div><hr><h2 id="self-review-patterns" tabindex="-1">Self-Review Patterns <a class="header-anchor" href="#self-review-patterns" aria-label="Permalink to &quot;Self-Review Patterns&quot;">​</a></h2><p>Beyond automated verification, some agents implement self-review — using the LLM itself to evaluate its own output.</p><h3 id="diff-review" tabindex="-1">Diff Review <a class="header-anchor" href="#diff-review" aria-label="Permalink to &quot;Diff Review&quot;">​</a></h3><p>The agent re-reads the diff of its changes and evaluates them:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Agent generates edit → Apply → Generate diff →</span></span>
<span class="line"><span>Feed diff back to agent: &quot;Review this diff for correctness&quot; →</span></span>
<span class="line"><span>Agent identifies issues → Fix → Re-verify</span></span></code></pre></div><p><strong>Claude Code</strong>&#39;s three-phase loop (gather → act → verify) includes this as the verify phase. The model reviews its own changes before considering the task complete.</p><h3 id="separate-reviewer-model" tabindex="-1">Separate Reviewer Model <a class="header-anchor" href="#separate-reviewer-model" aria-label="Permalink to &quot;Separate Reviewer Model&quot;">​</a></h3><p>Some architectures use a different model for review:</p><ul><li><strong>Junie CLI</strong> routes verification to potentially different models — Flash for quick checks, Opus for deep analysis</li><li><strong>Aider&#39;s architect mode</strong> separates the reasoning model (designs solution) from the editing model (implements it), creating a natural review boundary</li><li><strong>ForgeCode&#39;s Sage agent</strong> provides read-only deep analysis that acts as a review step</li></ul><h3 id="self-review-limitations" tabindex="-1">Self-Review Limitations <a class="header-anchor" href="#self-review-limitations" aria-label="Permalink to &quot;Self-Review Limitations&quot;">​</a></h3><p>Self-review has a fundamental limitation: the same model that made the mistake is asked to find the mistake. Research shows that LLMs are better at catching <em>other</em> models&#39; errors than their own. This is why multi-agent approaches (where a different agent reviews) tend to outperform single-agent self-review.</p><hr><h2 id="ci-cd-integration" tabindex="-1">CI/CD Integration <a class="header-anchor" href="#ci-cd-integration" aria-label="Permalink to &quot;CI/CD Integration&quot;">​</a></h2><p>Several agents integrate with continuous integration systems, either consuming CI results or triggering CI pipelines:</p><table tabindex="0"><thead><tr><th>Agent</th><th>CI/CD Integration</th><th>Mechanism</th></tr></thead><tbody><tr><td><strong>Droid</strong></td><td>GitHub Actions repair</td><td>Monitors CI failures, auto-fixes</td></tr><tr><td><strong>Codex</strong></td><td>Sandbox-isolated builds</td><td>Runs build in bubblewrap sandbox</td></tr><tr><td><strong>Claude Code</strong></td><td>User-configured commands</td><td>Model runs test/build commands</td></tr><tr><td><strong>Goose</strong></td><td>Extension-provided</td><td>CI integration via extensions</td></tr><tr><td><strong>Warp</strong></td><td>Terminal-native</td><td>Monitors build output in PTY</td></tr><tr><td><strong>OpenHands</strong></td><td>Docker-isolated</td><td>Full test suite in container</td></tr></tbody></table><p><strong>Droid</strong> has the most sophisticated CI integration — it monitors GitHub Actions workflows, detects failures, analyzes logs, and automatically generates fixes. This closes the loop between CI and the coding agent.</p><hr><h2 id="cross-agent-verification-summary" tabindex="-1">Cross-Agent Verification Summary <a class="header-anchor" href="#cross-agent-verification-summary" aria-label="Permalink to &quot;Cross-Agent Verification Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agent</th><th>Auto-Test</th><th>Auto-Lint</th><th>Type Check</th><th>Build Verify</th><th>Self-Review</th><th>Rollback</th><th>CI/CD</th></tr></thead><tbody><tr><td><strong>ForgeCode</strong></td><td>Enforced</td><td>Enforced</td><td>Via build</td><td>Enforced</td><td>Sage agent</td><td>Turn-level</td><td>—</td></tr><tr><td><strong>Claude Code</strong></td><td>Model-driven</td><td>Model-driven</td><td>Model-driven</td><td>Model-driven</td><td>3-phase loop</td><td>Checkpoints</td><td>User commands</td></tr><tr><td><strong>Codex</strong></td><td>Model-driven</td><td>Model-driven</td><td>Model-driven</td><td>Sandbox</td><td>—</td><td>Undo/redo</td><td>Sandbox builds</td></tr><tr><td><strong>Aider</strong></td><td><code>--auto-test</code></td><td><code>--auto-lint</code></td><td>Via lint cmd</td><td>Via test cmd</td><td>Architect mode</td><td>Git commits</td><td>—</td></tr><tr><td><strong>Junie CLI</strong></td><td>Verify phase</td><td>Verify phase</td><td>Via build</td><td>Via build</td><td>Diagnose phase</td><td>—</td><td>—</td></tr><tr><td><strong>OpenHands</strong></td><td>Agent-driven</td><td>Agent-driven</td><td>Agent-driven</td><td>Docker</td><td>StuckDetector</td><td>Event stream</td><td>Docker</td></tr><tr><td><strong>Droid</strong></td><td>Enforced</td><td>Enforced</td><td>Via build</td><td>Via build</td><td>Spec review</td><td>—</td><td>GitHub Actions</td></tr><tr><td><strong>Goose</strong></td><td>Extension</td><td>Extension</td><td>Extension</td><td>Extension</td><td>—</td><td>—</td><td>Extension</td></tr><tr><td><strong>Gemini CLI</strong></td><td>Model-driven</td><td>Model-driven</td><td>Model-driven</td><td>Model-driven</td><td>—</td><td>—</td><td>User commands</td></tr><tr><td><strong>OpenCode</strong></td><td>User config</td><td>User config</td><td>User config</td><td>User config</td><td>—</td><td>—</td><td>—</td></tr><tr><td><strong>Warp</strong></td><td>AI detection</td><td>AI detection</td><td>AI detection</td><td>AI detection</td><td>—</td><td>—</td><td>Terminal</td></tr><tr><td><strong>mini-SWE-agent</strong></td><td>Agent-driven</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td></tr><tr><td><strong>Pi</strong></td><td>Extension</td><td>Extension</td><td>Extension</td><td>Extension</td><td>—</td><td>—</td><td>—</td></tr><tr><td><strong>Ante</strong></td><td>Sub-agent</td><td>Sub-agent</td><td>Sub-agent</td><td>Sub-agent</td><td>Meta-agent</td><td>—</td><td>—</td></tr><tr><td><strong>Sage Agent</strong></td><td>Pipeline</td><td>Pipeline</td><td>—</td><td>—</td><td>Observation</td><td>—</td><td>—</td></tr><tr><td><strong>TongAgents</strong></td><td>Multi-agent</td><td>—</td><td>—</td><td>—</td><td>Cross-agent</td><td>—</td><td>—</td></tr><tr><td><strong>Capy</strong></td><td>Build phase</td><td>Build phase</td><td>Build phase</td><td>Build phase</td><td>Captain review</td><td>—</td><td>—</td></tr></tbody></table><hr><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ol><li><p><strong>Enforce, don&#39;t prompt</strong> — The single most impactful design decision. Runtime enforcement beats prompt instructions every time. ForgeCode proved this empirically.</p></li><li><p><strong>Fast checks first</strong> — The verification hierarchy is a cost optimization. Syntax checks in milliseconds catch errors that would waste minutes of test execution time.</p></li><li><p><strong>Truncate aggressively</strong> — Aider&#39;s 50-line rule is counterintuitive but well-supported. More error output hurts more than it helps. Models need focused, actionable errors.</p></li><li><p><strong>2–3 retries maximum</strong> — Diminishing returns are sharp. If the agent hasn&#39;t fixed it in 3 attempts, it needs a different approach, not another retry.</p></li><li><p><strong>Git is your safety net</strong> — Agents that commit after every successful step (Aider) have trivial rollback. Agents without rollback mechanisms are fragile.</p></li><li><p><strong>Multi-model verification beats self-review</strong> — Using a different model (or a different agent role) for review catches errors that self-review misses.</p></li><li><p><strong>User configuration scales poorly</strong> — Requiring users to specify lint/test commands works for power users but fails for onboarding. The trend is toward auto-detection and enforcement.</p></li></ol><hr><h2 id="topic-index" tabindex="-1">Topic Index <a class="header-anchor" href="#topic-index" aria-label="Permalink to &quot;Topic Index&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Description</th></tr></thead><tbody><tr><td><a href="./"><code>README.md</code></a></td><td>This file — overview of testing and verification patterns</td></tr><tr><td><a href="./agent-comparison.html"><code>agent-comparison.md</code></a></td><td>Detailed cross-agent comparison of verification strategies</td></tr><tr><td><a href="./build-verification.html"><code>build-verification.md</code></a></td><td>Build and compilation verification patterns</td></tr><tr><td><a href="./ci-cd-integration.html"><code>ci-cd-integration.md</code></a></td><td>CI/CD pipeline integration and automation</td></tr><tr><td><a href="./lint-integration.html"><code>lint-integration.md</code></a></td><td>Linter integration across languages and agents</td></tr><tr><td><a href="./rollback-strategies.html"><code>rollback-strategies.md</code></a></td><td>Rollback, undo, and recovery mechanisms</td></tr><tr><td><a href="./self-review.html"><code>self-review.md</code></a></td><td>Self-review and AI-assisted code review patterns</td></tr><tr><td><a href="./test-driven-development.html"><code>test-driven-development.md</code></a></td><td>Test-driven workflows and test generation</td></tr><tr><td><a href="./type-checking.html"><code>type-checking.md</code></a></td><td>Type checking integration (tsc, mypy, pyright)</td></tr></tbody></table><hr><h2 id="real-world-implementations" tabindex="-1">Real-World Implementations <a class="header-anchor" href="#real-world-implementations" aria-label="Permalink to &quot;Real-World Implementations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agent</th><th>Verification Approach</th><th>Reference</th></tr></thead><tbody><tr><td><strong>ForgeCode</strong></td><td>Programmatic enforcement, Sage review agent, biggest benchmark impact</td><td><a href="./../agents/forgecode/testing-and-verification.html"><code>../agents/forgecode/testing-and-verification.md</code></a></td></tr><tr><td><strong>Claude Code</strong></td><td>Model-driven 3-phase loop (gather → act → verify), checkpoints</td><td><a href="./../agents/claude-code/testing-and-verification.html"><code>../agents/claude-code/testing-and-verification.md</code></a></td></tr><tr><td><strong>Codex</strong></td><td>Sandbox-isolated builds, undo/redo, model-driven verification</td><td><a href="./../agents/codex/testing-and-verification.html"><code>../agents/codex/testing-and-verification.md</code></a></td></tr><tr><td><strong>Aider</strong></td><td>Gold-standard E-A-V loop, --auto-lint, --auto-test, 50-line truncation</td><td><a href="./../agents/aider/testing-and-verification.html"><code>../agents/aider/testing-and-verification.md</code></a></td></tr><tr><td><strong>OpenHands</strong></td><td>Docker-isolated tests, StuckDetector, event-stream rollback</td><td><a href="./../agents/openhands/testing-and-verification.html"><code>../agents/openhands/testing-and-verification.md</code></a></td></tr><tr><td><strong>Junie CLI</strong></td><td>First-class Verify phase, multi-model Diagnose escalation</td><td><a href="./../agents/junie-cli/testing-and-verification.html"><code>../agents/junie-cli/testing-and-verification.md</code></a></td></tr><tr><td><strong>Droid</strong></td><td>CI/CD repair, GitHub Actions monitoring, enforced verification</td><td><a href="./../agents/droid/testing-and-verification.html"><code>../agents/droid/testing-and-verification.md</code></a></td></tr><tr><td><strong>Goose</strong></td><td>Extension-based verification, MOIM context injection</td><td><a href="./../agents/goose/testing-and-verification.html"><code>../agents/goose/testing-and-verification.md</code></a></td></tr><tr><td><strong>Gemini CLI</strong></td><td>Model-driven with tool scheduler, parallel read-only checks</td><td><a href="./../agents/gemini-cli/testing-and-verification.html"><code>../agents/gemini-cli/testing-and-verification.md</code></a></td></tr><tr><td><strong>OpenCode</strong></td><td>User-configured lint/test commands, settings-driven</td><td><a href="./../agents/opencode/testing-and-verification.html"><code>../agents/opencode/testing-and-verification.md</code></a></td></tr><tr><td><strong>Warp</strong></td><td>Active AI error detection, PTY-native terminal monitoring</td><td><a href="./../agents/warp/testing-and-verification.html"><code>../agents/warp/testing-and-verification.md</code></a></td></tr><tr><td><strong>mini-SWE-agent</strong></td><td>Minimal — agent-driven bash commands, fixed iteration limit</td><td><a href="./../agents/mini-swe-agent/testing-and-verification.html"><code>../agents/mini-swe-agent/testing-and-verification.md</code></a></td></tr><tr><td><strong>Pi</strong></td><td>Extension-based lint/test hooks on tool events</td><td><a href="./../agents/pi-coding-agent/testing-and-verification.html"><code>../agents/pi-coding-agent/testing-and-verification.md</code></a></td></tr><tr><td><strong>Ante</strong></td><td>Multi-agent fan-out/fan-in, sub-agent verification</td><td><a href="./../agents/ante/testing-and-verification.html"><code>../agents/ante/testing-and-verification.md</code></a></td></tr><tr><td><strong>Sage Agent</strong></td><td>Linear pipeline with Observation feedback loop</td><td><a href="./../agents/sage-agent/testing-and-verification.html"><code>../agents/sage-agent/testing-and-verification.md</code></a></td></tr><tr><td><strong>TongAgents</strong></td><td>Multi-agent cross-verification, benchmark-driven</td><td><a href="./../agents/tongagents/testing-and-verification.html"><code>../agents/tongagents/testing-and-verification.md</code></a></td></tr><tr><td><strong>Capy</strong></td><td>Captain/Build phase separation, Ubuntu VM isolation</td><td><a href="./../agents/capy/testing-and-verification.html"><code>../agents/capy/testing-and-verification.md</code></a></td></tr></tbody></table>`,151)])])}const u=s(o,[["render",i]]);export{g as __pageData,u as default};
